import{_ as o,a as d,ai as t,o as i}from"./chunks/framework.Dc1yMVMM.js";const u=JSON.parse('{"title":"PC 项目困/难点总结","description":"","frontmatter":{},"headers":[],"relativePath":"workLog/work_project.md","filePath":"workLog/work_project.md","lastUpdated":1772787983000}'),l={name:"workLog/work_project.md"};function c(r,e,a,n,s,p){return i(),d("div",null,e[0]||(e[0]=[t('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /grady/workLog/work_project.md for this page in Markdown format</div><h1 id="pc-项目困-难点总结" tabindex="-1">PC 项目困/难点总结 <a class="header-anchor" href="#pc-项目困-难点总结" aria-label="Permalink to &quot;PC 项目困/难点总结&quot;">​</a></h1><blockquote><p>适用于面试准备，提炼技术难点与解决方案</p></blockquote><hr><h2 id="一、项目概览" tabindex="-1">一、项目概览 <a class="header-anchor" href="#一、项目概览" aria-label="Permalink to &quot;一、项目概览&quot;">​</a></h2><ul><li><strong>项目名称</strong>：云 DMS（经销商管理系统）</li><li><strong>技术栈</strong>：Vue 2.x + Vuex + Vue Router + Element UI + Axios + Webpack 4</li><li><strong>业务领域</strong>：汽车经销商售后管理（维修、索赔、配件、结算、客户等）</li><li><strong>规模</strong>：2000+ 前端文件，多微服务后端对接</li></ul><hr><h2 id="二、核心技术难点" tabindex="-1">二、核心技术难点 <a class="header-anchor" href="#二、核心技术难点" aria-label="Permalink to &quot;二、核心技术难点&quot;">​</a></h2><h3 id="_1-权限与认证体系" tabindex="-1">1. 权限与认证体系 <a class="header-anchor" href="#_1-权限与认证体系" aria-label="Permalink to &quot;1. 权限与认证体系&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li><strong>多级权限</strong>：菜单级 + 页面级 + 按钮级（<code>authList</code> / <code>authMark</code>）权限控制</li><li><strong>多种登录方式</strong>：OAuth2 授权码模式、DOS Token、API 直连（<code>getTokenByApi</code>）</li><li><strong>白名单管理</strong>：<code>whiteList</code>（免登录）、<code>whiteAuth</code>（免权限）、<code>whiteSite</code>（内网免登录）</li><li><strong>SSO 集成</strong>：与 Dealer Portal 单点登录对接，需处理 <code>code</code> 换取 <code>token</code>、重定向等</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>router.beforeEach</code> 中统一鉴权，未登录则拉取 navList，无权限跳 404</li><li><code>formateMenu</code> 递归扁平化树形菜单，用于路径权限校验</li><li><code>MultiuseButton</code> 通过 <code>authList.includes(authMark)</code> 控制按钮显隐</li></ul><hr><h3 id="_2-api-签名与安全" tabindex="-1">2. API 签名与安全 <a class="header-anchor" href="#_2-api-签名与安全" aria-label="Permalink to &quot;2. API 签名与安全&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>所有请求需携带 <strong>MD5 签名</strong>（<code>signMd5Utils</code>）</li><li>签名规则：<code>md5(JSON.stringify(升序参数) + secret_key).toUpperCase()</code></li><li><code>secret_key</code> 由 <code>sessionStorage.appIdKey</code> 经 DES 解密得到</li><li>GET/POST/DELETE 参数处理方式不同（URL 参数、body、数组序列化）</li><li>需兼容 <code>|</code> 分隔的日期范围等特殊参数</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>fetchApi.post/get/put/delete</code> 统一封装，自动拼 <code>sign</code>、<code>timestamp</code></li><li><code>urlToJson</code> 分离需签名参数与直接拼接的 <code>originStringQuery</code></li><li><code>signMd5Utils.getSign</code> 支持数组参数 <code>arrayString</code> 序列化</li></ul><hr><h3 id="_3-动态菜单与路由管理" tabindex="-1">3. 动态菜单与路由管理 <a class="header-anchor" href="#_3-动态菜单与路由管理" aria-label="Permalink to &quot;3. 动态菜单与路由管理&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>菜单由后端接口按 <code>roleId</code> 返回，需与本地 <code>menu.js</code> 路由映射</li><li>多级菜单递归渲染（<code>menuTree.js</code> 中 <code>createMenuTree</code>）</li><li>图标、<code>hideInMenu</code> 等属性需从路由表 <code>deepFind</code> 补齐</li><li>支持外链菜单（<code>/^https?:\\/\\//.test(key)</code>）</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>deepMenu</code> 将接口数据转为前端菜单结构</li><li><code>formateNavList</code> 与 <code>routesMap</code> 匹配，补全 <code>icon</code>、<code>hideInMenu</code></li><li>JSX 渲染 <code>el-submenu</code> / <code>el-menu-item</code>，递归处理 <code>children</code></li></ul><hr><h3 id="_4-keepalive-与多-tab-缓存" tabindex="-1">4. KeepAlive 与多 Tab 缓存 <a class="header-anchor" href="#_4-keepalive-与多-tab-缓存" aria-label="Permalink to &quot;4. KeepAlive 与多 Tab 缓存&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>头部 Tab 需缓存页面状态，但存在 <code>maxCacheNum: 10</code> 限制</li><li><code>keep-alive :include</code> 需动态维护 <code>cachedNames</code>（组件名列表）</li><li>关闭 Tab 时要 <code>removeKeepAliveNames</code>，否则内存泄漏</li><li><strong>Iframe 页面</strong>需单独管理 <code>iframeComponentsArr</code>，支持动态注册、<code>v-show</code> 切换</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>MultiTab</code> 监听 <code>$route</code>，对 <code>meta.keepAlive</code> 的页面调用 <code>addKeepAliveNames</code></li><li><code>RouteView</code> 中 <code>cachedNames = [&#39;RouteView&#39;, ...keepAliveNames.map(x =&gt; x.value)]</code></li><li>超限时 <code>Notification.warning</code> 提示，并 <code>next(false)</code> 阻止跳转</li></ul><hr><h3 id="_5-虚拟滚动组件-virtualscroll" tabindex="-1">5. 虚拟滚动组件（VirtualScroll） <a class="header-anchor" href="#_5-虚拟滚动组件-virtualscroll" aria-label="Permalink to &quot;5. 虚拟滚动组件（VirtualScroll）&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>自研虚拟滚动，支持 <strong>固定行高</strong>（<code>itemSize</code>）与 <strong>动态行高</strong>（<code>sizeField</code> / <code>minItemSize</code>）</li><li>支持垂直/水平方向、<code>pageMode</code>（基于文档滚动）</li><li>使用 <code>pool</code> 复用 DOM、<code>$_views</code> / <code>$_unusedViews</code> 管理视图实例</li><li><code>buffer</code> 预渲染区域、<code>scrollToItem</code> / <code>scrollToPosition</code> 等能力</li></ul><p><strong>实现要点</strong>：</p><ul><li>通过 <code>sizes</code> 累加计算每项位置，<code>updateVisibleItems</code> 决定可见项</li><li><code>will-change: transform</code> + <code>translateY/X</code> 优化渲染</li><li><code>DynamicScroll</code> 支持 <code>getItemSize</code> 回调，适配高度不定的场景</li></ul><hr><h3 id="_6-复杂表格组件-basetable" tabindex="-1">6. 复杂表格组件（BaseTable） <a class="header-anchor" href="#_6-复杂表格组件-basetable" aria-label="Permalink to &quot;6. 复杂表格组件（BaseTable）&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li><code>pageTable.vue</code> 2000+ 行，集成筛选、排序、分页、导出、列过滤</li><li>支持服务端排序（<code>isServerSorter</code>）、服务端筛选（<code>isServerFilter</code>）</li><li>多数据源形态：<code>dataSource</code> 为数组或 <code>{ items, total }</code></li><li>列配置复杂：<code>columnsRef</code>、<code>rowstyles</code>、<code>cellstyles</code>、<code>selectionType</code> 等</li><li>需与 <code>TopFilter</code>、<code>ColumnFilter</code>、<code>ExportExcel</code>、<code>Pagination</code> 等子组件联动</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>mergeProps</code>、<code>getOptionProps</code> 统一处理 props 透传</li><li><code>fetchapi</code> 统一封装请求，支持 <code>params</code>、<code>uidkey</code>、<code>datakey</code> 适配不同接口</li><li>支持 <code>defaultSelections</code> 预选、<code>selectionType: single|multiple</code></li></ul><hr><h3 id="_7-按需加载与懒加载-tab" tabindex="-1">7. 按需加载与懒加载 Tab <a class="header-anchor" href="#_7-按需加载与懒加载-tab" aria-label="Permalink to &quot;7. 按需加载与懒加载 Tab&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li><code>LazyLoadTab</code> 通过 <code>require([</code>@/pages/${path}<code>], resolve)</code> 动态加载 Tab 内容</li><li>需解决 <code>path</code> 与组件名的映射（<code>tabMenus</code> 中 <code>title</code> 对应路径）</li><li><code>destroyOnClose</code> 控制 Tab 切换时是否销毁子组件</li><li>非当前 Tab 不渲染（<code>lazy</code>），减少首屏开销</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>loadComponent</code> 在 <code>activeName</code> 变化时注册组件</li><li><code>createTabPanel</code> 中用 <code>h(this.$options.components[x.title], ...)</code> 渲染</li><li><code>keep-alive</code> 包裹或按需 <code>isCurrent ? component : null</code></li></ul><hr><h3 id="_8-构建与性能优化" tabindex="-1">8. 构建与性能优化 <a class="header-anchor" href="#_8-构建与性能优化" aria-label="Permalink to &quot;8. 构建与性能优化&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>项目体积大，需 <code>--max-old-space-size=8192</code> 避免 Node 内存溢出</li><li>多微服务导致依赖分散，需合理的 <code>splitChunks</code> 策略</li><li><code>element-ui</code> 单独拆包（<code>app-elementUI</code>）、公共组件拆包（<code>app-commons</code>）</li><li><code>maxSize: 9000000</code> 控制单 chunk 大小，<code>maxInitialRequests: 4</code> 控制初始请求数</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>splitChunks.cacheGroups</code> 区分 libs、elementUI、commons</li><li><code>chunkFilename</code> 使用 <code>[chunkhash:8]</code> 利于缓存</li><li>开发环境 <code>cheap-source-map</code>，生产可关闭 <code>productionSourceMap</code></li></ul><hr><h3 id="_9-第三方-iframe-集成" tabindex="-1">9. 第三方 Iframe 集成 <a class="header-anchor" href="#_9-第三方-iframe-集成" aria-label="Permalink to &quot;9. 第三方 Iframe 集成&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>多个第三方系统（订购、VMS、ETKA 等）通过 iframe 嵌入</li><li>URL 需动态拼接：<code>token</code>、<code>userId</code>、<code>pagetype</code> 等，部分需 MD5 加密</li><li><code>postMessage</code> 与 iframe 内页面通信（如 <code>partEtkaInfo</code> 传 <code>sstCode</code>）</li><li>需与 <code>keep-alive</code>、Tab 关闭逻辑配合，避免 iframe 残留</li><li>iframe 高度需根据布局动态计算（<code>footer - top</code>）</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>getUrl</code> 中 <code>queryOEMDefaultParaValueByCode</code> 获取基础 URL</li><li>Token 格式：<code>userId#timestamp#DMS#md5(secret)</code> 等</li><li><code>RouteView</code> 中 <code>iframeComponentsArr</code>、<code>hasOpenComponentsArr</code> 控制 iframe 组件的注册与显示</li></ul><hr><h3 id="_10-防重复提交与业务校验" tabindex="-1">10. 防重复提交与业务校验 <a class="header-anchor" href="#_10-防重复提交与业务校验" aria-label="Permalink to &quot;10. 防重复提交与业务校验&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>按钮级防重复：<code>MultiuseButton</code> 通过 <code>ajaxing</code> 状态 + <code>sleep(200)</code> 防抖</li><li>业务层重复校验：如配件订购的 <code>checkRepeatPartList</code> 校验重复件</li><li>异常件限制：<code>preErrorPartList</code>、<code>showPartExistsOrderDialog</code> 等复杂分支</li><li>多步骤提交流程中的状态管理与回滚</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>clickHandler</code> 中 <code>ajaxing = true</code>，<code>await this.click()</code> 后 <code>ajaxing = false</code></li><li><code>isDisabled = ajaxing || disabled</code> 控制按钮不可用</li><li>业务侧需区分「继续提交」「取消」等用户选择，并串联后续校验逻辑</li></ul><hr><h3 id="_11-websocket-实时通知" tabindex="-1">11. WebSocket 实时通知 <a class="header-anchor" href="#_11-websocket-实时通知" aria-label="Permalink to &quot;11. WebSocket 实时通知&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>需与后端 WebSocket 服务建立长连接（<code>sockectNew.js</code>）</li><li>连接状态管理（<code>isOpen</code>）、重连、心跳等</li><li>与 Vuex 集成，消息需驱动全局通知（如 <code>createPromotionNotify</code>）</li><li>多 Tab 场景下消息处理的归属与去重</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>ConnectWebsocket</code> 封装连接逻辑，<code>getWSUrl</code> 从配置或 session 获取地址</li><li>消息到达后通过 Vuex action 更新状态，触发 UI 展示</li></ul><hr><h3 id="_12-多环境与微服务代理" tabindex="-1">12. 多环境与微服务代理 <a class="header-anchor" href="#_12-多环境与微服务代理" aria-label="Permalink to &quot;12. 多环境与微服务代理&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>开发环境需配置大量 <code>proxyTable</code>（<code>/clouddms</code>、<code>/dms.part</code>、<code>/dms.claim</code> 等）</li><li>各服务独立部署，地址可能随环境变化</li><li>需区分 development / test / production，<code>config.serverUrl</code> 等动态切换</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>config/index.js</code> 中 <code>proxyTable</code> 按服务拆分</li><li><code>pathRewrite</code> 统一前缀，<code>changeOrigin</code> 解决跨域</li><li><code>.env</code>、<code>dotenv-webpack</code> 管理环境变量</li></ul><hr><h3 id="_13-打印功能" tabindex="-1">13. 打印功能 <a class="header-anchor" href="#_13-打印功能" aria-label="Permalink to &quot;13. 打印功能&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li><strong>多端适配</strong>：PC 端 Lodop 控件、非插件浏览器 CLodop 云打印、移动端/平板 C-Lodop、纯浏览器 <code>window.print</code></li><li><strong>Lodop vs CLodop</strong>：<code>needCLodop()</code> 根据 UA 判断（Chrome 41+、Firefox 41+、Edge、移动端等需 CLodop），旧版 IE 用 ActiveX 插件</li><li><strong>模板动态加载</strong>：<code>BasePrint</code> 按 <code>template</code> 从 <code>printTemplate/</code> 动态 <code>require</code> 打印模板组件</li><li><strong>样式与分页</strong>：Vue 的 <code>break-after: page</code> 需替换为 <code>page-break-after: always</code>；全局 style 注入</li><li><strong>WebPrint（PDF）</strong>：PDF 通过 iframe + PDF.js 预览打印；IE 用 <code>/static/webPrint/pdf/web/viewer.html?file=</code></li><li><strong>打印配置服务</strong>：<code>configPrint</code> 接口管理打印机列表、类型，支持远程打印服务</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>getLodop()</code>：双端口 8000/18000 加载 CLodop，未安装时提示下载 <code>install_lodop32/64.exe</code>、<code>CLodop_Setup_for_Win32NT.exe</code></li><li><code>BasePrint</code>：<code>printerType</code>(laser/针打)、<code>direction</code>(vertical/horizontal)、<code>alwaysPrint</code>(连续纸)、<code>printCopies</code>、<code>ifPrintPreview</code>(直接打印/预览)</li><li><code>createPrintLogo</code>：表头注入经销商 logo、名称</li><li><code>$print(dom)</code> 插件：将 DOM 克隆到 iframe，处理 input/textarea/select 状态，<code>execCommand(&#39;print&#39;)</code> 或 <code>window.print()</code></li><li><code>clodopPad.js</code>：Pad 端走 HTTPS C-Lodop 服务（如 8443 端口）</li><li>独立打印页：<code>/print</code>、<code>/printPre</code>、<code>/appReceptionPrint</code>、<code>/balanceApp</code> 等在 <code>whiteList</code>，供移动 App 或外链直接打开</li></ul><p><strong>打印模板体系</strong>：</p><ul><li>维修工单、预检单、结算单、索赔单、配件出入库单、工具借还单、领料单等 30+ 业务模板</li><li>模板统一放在 <code>printTemplate/</code>，通过 <code>data</code>、<code>fileAddress</code>、<code>updateDate</code> 等 props 传参</li></ul><hr><h2 id="三、业务复杂度相关" tabindex="-1">三、业务复杂度相关 <a class="header-anchor" href="#三、业务复杂度相关" aria-label="Permalink to &quot;三、业务复杂度相关&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>复杂度说明</th></tr></thead><tbody><tr><td>维修接待</td><td>多 Tab、配件建议、工单打印、Lodop 打印集成</td></tr><tr><td>配件订购</td><td>购物车、重复件校验、异常件限制、ETKA iframe 集成</td></tr><tr><td>索赔管理</td><td>预索赔、三包、QA 等多子业务，流程分支多</td></tr><tr><td>结算</td><td>工单结算、索赔结算、败诉结算等，数据结构复杂</td></tr><tr><td>报表</td><td>ECharts 图表、多维度筛选、Excel 导出</td></tr><tr><td><strong>打印</strong></td><td><strong>BasePrint(Lodop) / WebPrint(PDF) / $print(DOM) / CLodop 云打印 / Pad 端 C-Lodop；30+ 业务模板；打印机配置服务</strong></td></tr></tbody></table><hr><h2 id="四、面试可展开的技术点" tabindex="-1">四、面试可展开的技术点 <a class="header-anchor" href="#四、面试可展开的技术点" aria-label="Permalink to &quot;四、面试可展开的技术点&quot;">​</a></h2><ol><li><p><strong>如何设计并实现前后端 API 签名机制？</strong><br> → 参数升序、MD5、密钥解密、GET/POST 差异化处理</p></li><li><p><strong>Vue 中如何实现多级菜单的递归渲染与权限控制？</strong><br> → 树形数据、递归组件、路由守卫、<code>formateMenu</code> 扁平化</p></li><li><p><strong>KeepAlive 缓存数量受限时如何处理？</strong><br> → maxCacheNum、动态 include、Tab 关闭时 remove、iframe 单独管理</p></li><li><p><strong>虚拟滚动的核心原理是什么？</strong><br> → 可视区域计算、DOM 复用、transform 定位、动态高度累加</p></li><li><p><strong>大型 Vue 项目的构建优化有哪些？</strong><br> → splitChunks、按需加载、内存限制、sourceMap 策略</p></li><li><p><strong>如何安全地与 iframe 内第三方页面通信？</strong><br> → postMessage、token 传递、targetOrigin 限制、生命周期清理</p></li><li><p><strong>企业级打印方案如何适配 PC、移动端、无插件浏览器？</strong><br> → Lodop 控件、CLodop 云打印、needCLodop 判断、Pad HTTPS 服务、$print 纯浏览器方案、PDF iframe 打印</p></li></ol><hr><h2 id="五、总结" tabindex="-1">五、总结 <a class="header-anchor" href="#五、总结" aria-label="Permalink to &quot;五、总结&quot;">​</a></h2><p>本项目综合了 <strong>企业级权限、API 安全、大型表格、虚拟滚动、多 Tab 缓存、iframe 集成、多端打印、构建优化</strong> 等前端常见难点，适合在面试中结合实际模块展开说明解决方案与个人贡献。</p><h1 id="dms-维修移动端项目-难点-挑战总结" tabindex="-1">DMS 维修移动端项目 - 难点/挑战总结 <a class="header-anchor" href="#dms-维修移动端项目-难点-挑战总结" aria-label="Permalink to &quot;DMS 维修移动端项目 - 难点/挑战总结&quot;">​</a></h1><blockquote><p>面向面试的项目难点提炼，便于阐述技术深度与解决思路</p></blockquote><hr><h2 id="一、项目概述" tabindex="-1">一、项目概述 <a class="header-anchor" href="#一、项目概述" aria-label="Permalink to &quot;一、项目概述&quot;">​</a></h2><ul><li><strong>项目名称</strong>：new-app-repair（DMS 维修移动端）</li><li><strong>技术栈</strong>：Vue 3 + Vite 7 + TypeScript + Pinia + Vant 4</li><li><strong>业务域</strong>：4S 店维修接车、委托书、结算、终检、索赔验真等全流程</li><li><strong>运行环境</strong>：企业微信内嵌 H5，依赖企业微信 OAuth 与 JSSDK</li></ul><hr><h2 id="二、架构与集成类难点" tabindex="-1">二、架构与集成类难点 <a class="header-anchor" href="#二、架构与集成类难点" aria-label="Permalink to &quot;二、架构与集成类难点&quot;">​</a></h2><h3 id="_2-1-多微服务-api-治理" tabindex="-1">2.1 多微服务 API 治理 <a class="header-anchor" href="#_2-1-多微服务-api-治理" aria-label="Permalink to &quot;2.1 多微服务 API 治理&quot;">​</a></h3><p><strong>难点描述</strong>：后端为微服务架构，前端需对接 10+ 个 DMS 服务：</p><table tabindex="0"><thead><tr><th>服务</th><th>职责</th><th>典型场景</th></tr></thead><tbody><tr><td>DMS_REPAIR</td><td>维修核心</td><td>接车、派工、委托书、结算</td></tr><tr><td>DMS_COMMON</td><td>公共能力</td><td>登录、字典、OCR、参数配置</td></tr><tr><td>DMS_APP</td><td>移动端专用</td><td>车辆检查、技师、质检、增项</td></tr><tr><td>DMS_DATACENTER</td><td>数据中心</td><td>车主、会员、维修历史</td></tr><tr><td>DMS_OPSFILE</td><td>文件服务</td><td>图片上传、OSS</td></tr><tr><td>DMS_CLAIMCENTER</td><td>索赔中心</td><td>索赔验真</td></tr><tr><td>DMS_WORKSHOP</td><td>车间</td><td>派工</td></tr><tr><td>DMS_PART</td><td>配件</td><td>零件库存</td></tr></tbody></table><p><strong>挑战点</strong>：</p><ul><li>统一 baseURL、超时、错误码处理，同时区分不同服务路径</li><li>请求拦截器需注入 <code>accesstoken</code>、<code>userId</code>、<code>dealerCode</code>、<code>isApp</code>、<code>isFeign</code> 等公共头</li><li>接口按业务模块拆分（<code>api/repair</code>、<code>api/common</code>、<code>api/balance</code> 等），URL 使用 <code>server.ts</code> 中的前缀常量，维护成本高</li></ul><hr><h3 id="_2-2-企业微信-oauth-jssdk-接入" tabindex="-1">2.2 企业微信 OAuth + JSSDK 接入 <a class="header-anchor" href="#_2-2-企业微信-oauth-jssdk-接入" aria-label="Permalink to &quot;2.2 企业微信 OAuth + JSSDK 接入&quot;">​</a></h3><p><strong>难点描述</strong>：登录与 SDK 依赖企业微信，流程复杂、调试受限。</p><p><strong>登录流程</strong>：</p><ol><li>无 token 时重定向至企业微信 <code>oauth2/authorize</code></li><li>回调带 <code>code</code>，在 <code>router.beforeEach</code> 中调用 <code>wechatLogin</code> 换取 token</li><li>登录成功写入 <code>useMainStore</code>，持久化至 sessionStorage</li><li>白名单页面（<code>/videoShow</code>、<code>/diagnosticReport</code> 等）可跳过鉴权</li></ol><p><strong>JSSDK 初始化</strong>：</p><ul><li>需调用 <code>corpJsapiTicket</code> / <code>agentJsapiTicket</code> 获取签名</li><li>签名与当前 URL 强绑定，SPA 路由变化后需重新 config</li><li>多处页面（接车、结算、委托书、扫码等）复用同一套 <code>corpJsapiTicket</code> + 初始化逻辑</li><li>开发环境需 mock，避免本地 URL 与签名不匹配</li></ul><p><strong>可提炼的面试点</strong>：OAuth2、路由守卫与登录状态联动、URL 动态签名、企业微信 JSAPI 权限管理。</p><hr><h3 id="_2-3-蓝牙-obd-检测集成" tabindex="-1">2.3 蓝牙 / OBD 检测集成 <a class="header-anchor" href="#_2-3-蓝牙-obd-检测集成" aria-label="Permalink to &quot;2.3 蓝牙 / OBD 检测集成&quot;">​</a></h3><p><strong>难点描述</strong>：接车阶段需通过蓝牙 OBD 设备做 ECU 检测、故障码读取，涉及企微 BLE API 与底层协议。</p><p><strong>技术链条</strong>：</p><ol><li><strong>企微 JSSDK</strong>：<code>openBluetoothAdapter</code>、<code>createBLEConnection</code>、<code>writeBLECharacteristicValue</code>、<code>notifyBLECharacteristicValueChange</code> 等</li><li><strong>BLE 协议</strong>：固定 UUID（SERVICE、Notify、Write），多种设备支持（如 2 套 UUID 映射）</li><li><strong>数据解析</strong>：二进制分包接收、<code>combineBluetoothPacket</code> 组包、<code>receiveMsgDeal</code> 解析 R04/R08/R13 等指令</li><li><strong>ECU / 故障码</strong>：<code>scanEcuInfo</code>、<code>scanErrorCode</code>，依赖 JSON 数据映射</li></ol><p><strong>OBD 数据管理</strong>：</p><ul><li>远程 JSON 为 gzip 压缩，需 <code>pako.ungzip</code> 解压</li><li>版本控制：远程版本 &gt; 本地版本则下载并写入 IndexedDB</li><li>使用 Dexie 做 <code>JsonDatabase</code> 封装，支持离线使用 OBD 故障码库</li></ul><p><strong>挑战点</strong>：</p><ul><li>企微 BLE 仅在企业微信客户端内可用，调试依赖真机</li><li>连接状态、ACC、车型解锁等状态需与业务层联动</li><li>设备兼容性（不同 OBD 设备 UUID、协议差异）</li></ul><hr><h2 id="三、业务与数据流难点" tabindex="-1">三、业务与数据流难点 <a class="header-anchor" href="#三、业务与数据流难点" aria-label="Permalink to &quot;三、业务与数据流难点&quot;">​</a></h2><h3 id="_3-1-接车-reception-业务复杂度" tabindex="-1">3.1 接车（reception）业务复杂度 <a class="header-anchor" href="#_3-1-接车-reception-业务复杂度" aria-label="Permalink to &quot;3.1 接车（reception）业务复杂度&quot;">​</a></h3><ul><li><strong>单文件体量</strong>：<code>reception/index.vue</code> 约 2344 行</li><li><strong>核心能力</strong>：VIN 输入/OCR、车辆信息拉取、维修历史（全国/本地）、OBD 检测、接车单保存、活动提醒、客户需求等</li><li><strong>数据依赖</strong>：DMS_REPAIR、DMS_DATACENTER、DMS_COMMON 多服务，接口调用链长、错误兜底复杂</li></ul><p><strong>面试可展开</strong>：如何拆分超大组件、状态管理策略、接口串并行与 loading 处理。</p><hr><h3 id="_3-2-委托书-结算-增项业务复用" tabindex="-1">3.2 委托书 / 结算 / 增项业务复用 <a class="header-anchor" href="#_3-2-委托书-结算-增项业务复用" aria-label="Permalink to &quot;3.2 委托书 / 结算 / 增项业务复用&quot;">​</a></h3><p><strong>难点</strong>：<code>labour</code>、<code>part</code>、<code>coupon</code>、<code>specialService</code>、<code>additional</code> 等组件在以下场景复用，逻辑和 UI 略有差异：</p><ul><li><code>repairOrder</code>（委托书）</li><li><code>repairOrderEdit</code>（委托书编辑）</li><li><code>repairAddItems</code>（维修增项）</li><li><code>repairSettlement</code>（维修结算）</li></ul><p>** challenge**：</p><ul><li>通过 props / 事件区分上下文，易产生分支判断和隐式耦合</li><li>优惠券、工单、套餐、活动等组合逻辑复杂，需清晰的数据流设计</li></ul><hr><h3 id="_3-3-在线健康检查-evhc-流程" tabindex="-1">3.3 在线健康检查（EVHC）流程 <a class="header-anchor" href="#_3-3-在线健康检查-evhc-流程" aria-label="Permalink to &quot;3.3 在线健康检查（EVHC）流程&quot;">​</a></h3><ul><li>覆盖：检查项编辑、增项、质检、服务顾问确认、客户签名等</li><li>组件层级深：<code>onlineHealthMergeForEvhc</code> 下多级 <code>components</code>（如 <code>onlineHealthEdit</code>、<code>onlineHealthQualityInspection</code>）</li><li>状态流转：技师保存 → 技师提交 → 质检退回/通过 → 顾问完成 → 客户签名</li><li>多角色：技师、质检、服务顾问、客户，权限与展示逻辑交织</li></ul><hr><h2 id="四、技术实现难点" tabindex="-1">四、技术实现难点 <a class="header-anchor" href="#四、技术实现难点" aria-label="Permalink to &quot;四、技术实现难点&quot;">​</a></h2><h3 id="_4-1-请求层-防重复、取消、错误处理" tabindex="-1">4.1 请求层：防重复、取消、错误处理 <a class="header-anchor" href="#_4-1-请求层-防重复、取消、错误处理" aria-label="Permalink to &quot;4.1 请求层：防重复、取消、错误处理&quot;">​</a></h3><p><strong>实现要点</strong>：</p><ul><li><code>addPending</code> / <code>removePending</code> 基于 <code>method + url + params + data</code> 生成 key，用 <code>Map</code> 管理待处理请求</li><li>使用 Axios <code>CancelToken</code> 取消重复请求</li><li><code>clearPending</code> 在路由跳转等场景清空 pending</li><li>错误码映射（400/401/403/500 等）统一 Toast 提示</li><li>网络异常（<code>!response</code>）时写入 localStorage 便于排查</li></ul><hr><h3 id="_4-2-离线与版本化存储-dexie" tabindex="-1">4.2 离线与版本化存储（Dexie） <a class="header-anchor" href="#_4-2-离线与版本化存储-dexie" aria-label="Permalink to &quot;4.2 离线与版本化存储（Dexie）&quot;">​</a></h3><ul><li><code>JsonDatabase</code> / <code>StableJsonDatabase</code> 基于 Dexie 封装</li><li>存储结构：<code>jsonData</code>（版本、数据、更新时间）、<code>metadata</code>（key-value）</li><li>写入带事务、重试（最多 3 次），失败时重置初始化状态</li><li>OBD 故障码 JSON 以压缩形式存储，按版本更新，支持弱网/离线场景</li></ul><hr><h3 id="_4-3-移动端适配" tabindex="-1">4.3 移动端适配 <a class="header-anchor" href="#_4-3-移动端适配" aria-label="Permalink to &quot;4.3 移动端适配&quot;">​</a></h3><ul><li><strong>rem 方案</strong>：postcss-pxtorem + <code>@unocss/preset-rem-to-px</code>（baseFontSize: 4）+ amfe-flexible</li><li><strong>样式变量</strong>：<code>variable.scss</code> 通过 Vite <code>additionalData</code> 全局注入</li><li><strong>UnoCSS</strong>：与 Vant、SCSS 共存，需注意优先级和原子类命名</li><li><strong>兼容性</strong>：<code>@vitejs/plugin-legacy</code> 支持 IE11、iOS 10，部分依赖需 polyfill</li></ul><hr><h3 id="_4-4-ocr-集成" tabindex="-1">4.4 OCR 集成 <a class="header-anchor" href="#_4-4-ocr-集成" aria-label="Permalink to &quot;4.4 OCR 集成&quot;">​</a></h3><ul><li>VIN 码、行驶证、车牌识别，调用 <code>DMS_COMMON</code> 下 <code>ocr/vehiclevin</code>、<code>ocr/vehiclelicense</code></li><li>图片需预处理（压缩、resize），与 <code>compressorjs</code> 等配合使用</li><li>结果解析、校验、回填表单，需处理识别失败、模糊等问题</li></ul><hr><h2 id="五、构建与工程化" tabindex="-1">五、构建与工程化 <a class="header-anchor" href="#五、构建与工程化" aria-label="Permalink to &quot;五、构建与工程化&quot;">​</a></h2><ul><li><strong>base</strong>：<code>/dmsapp/repair</code>，部署在子路径</li><li><strong>多环境</strong>：development / test / production，环境变量区分 API、企微 corpId 等</li><li><strong>代码分割</strong>：echarts 单独 chunk，<code>manualChunks</code> 控制包体积</li><li><strong>构建兼容</strong>：针对安卓微信内核的 ES5 兼容、terser 配置（含 vconsole eval 忽略）</li><li><strong>代理</strong>：<code>/clouddms</code>、<code>/lab-dms</code> 分别代理不同后端，支持本地联调</li></ul><hr><h2 id="六、面试回答提纲" tabindex="-1">六、面试回答提纲 <a class="header-anchor" href="#六、面试回答提纲" aria-label="Permalink to &quot;六、面试回答提纲&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题方向</th><th>可展开内容</th></tr></thead><tbody><tr><td>多服务 API 如何治理</td><td>server.ts 前缀常量、拦截器统一头、按业务拆 api 模块</td></tr><tr><td>企业微信登录流程</td><td>OAuth code 换取 token、路由守卫、白名单、sessionStorage 持久化</td></tr><tr><td>蓝牙 OBD 实现思路</td><td>企微 BLE API → 连接/读写 → 分包组包 → ECU/故障码 JSON 解析，Dexie 离线存储</td></tr><tr><td>超大页面如何拆分</td><td>按功能拆 components、hooks、store、services，按状态拆分步骤组件</td></tr><tr><td>请求防抖/取消</td><td>pending Map + CancelToken，路由跳转 clearPending</td></tr><tr><td>移动端适配方案</td><td>rem + pxtorem + UnoCSS + 设计变量</td></tr><tr><td>离线/弱网策略</td><td>Dexie IndexedDB 存 OBD JSON，版本控制 + 重试</td></tr></tbody></table><hr><h2 id="七、总结" tabindex="-1">七、总结 <a class="header-anchor" href="#七、总结" aria-label="Permalink to &quot;七、总结&quot;">​</a></h2><p>项目综合了 <strong>微服务 API 治理</strong>、<strong>企业微信生态集成</strong>、<strong>蓝牙/OBD 硬件协议</strong>、<strong>复杂维修业务流程</strong> 以及 <strong>移动端适配与工程化</strong> 等多类难点。在面试中可从「业务理解 → 技术选型 → 实现细节 → 踩坑与优化」顺序展开，体现对 DMS 维修领域和移动端 H5 的掌握程度。</p>',162)]))}const g=o(l,[["render",c]]);export{u as __pageData,g as default};
